import React, { useEffect, useState } from 'react';
import { useParams } from 'react-router-dom';
import axios from 'axios';
import './ProductDetail.css'; // 👈 CSS file import

const ProductDetail = () => {
  const { id } = useParams();
  const [product, setProduct] = useState(null);
  const [selectedImage, setSelectedImage] = useState("");

  useEffect(() => {
    axios.get(`http://localhost:5000/api/products/${id}`)
      .then(res => {
        setProduct(res.data);
        setSelectedImage(res.data.images?.[0]); // default image
      })
      .catch(err => console.error("Error fetching product:", err));
  }, [id]);

  if (!product) return <p>Loading...</p>;

  return (
    <div className="product-detail-container">
      
      {/* LEFT: Thumbnail images */}
      <div className="thumbnail-column">
        {product.images?.map((img, index) => (
          <img
            key={index}
            src={img}
            alt="thumbnail"
            className={`thumbnail ${selectedImage === img ? 'active' : ''}`}
            onClick={() => setSelectedImage(img)}
          />
        ))}
      </div>

      {/* CENTER: Main Image */}
      <div className="main-image">
        <img src={selectedImage} alt={product.name} />
      </div>

      {/* RIGHT: Info */}
      <div className="product-info">
        <h2>{product.brand}</h2>
        <h1>{product.name}</h1>
        <div className="price-section">
          <span className="price">₹{product.price}</span>
          <span className="original-price">₹{product.originalPrice}</span>
          <span className="offer">{Math.round(((product.originalPrice - product.price) / product.originalPrice) * 100)}% off</span>
        </div>
        <div className="rating">⭐ {product.rating}</div>

        <div className="sizes">
          <p>Available Sizes:</p>
          {product.sizes.map((size, i) => (
            <button key={i} className="size-btn">{size}</button>
          ))}
        </div>

        <div className="offers">
          <p>Available Offers:</p>
          <ul>
            {product.offers.map((offer, i) => (
              <li key={i}>💸 {offer}</li>
            ))}
          </ul>
        </div>

        <p className="description">{product.description}</p>
      </div>
    </div>
  );
};

export default ProductDetail;
